export const tasks: SeedTask[] = [
  // Bugs
  { title: "Correct broken breadcrumb navigation", description: "The breadcrumb navigation on nested pages shows incorrect hierarchy. When navigating from Dashboard > Settings > Profile, the breadcrumb displays Dashboard > Profile, skipping the Settings level. The issue is in the breadcrumb generator utility which splits the URL path but does not account for route groups in the Next.js App Router. This causes intermediate segments to be dropped from the displayed trail.", type: "bug", status: "qa", assigneeRole: "Product Manager", projectName: "Marketing Site" },
  { title: "Correct CSV export missing columns", description: "When exporting task data to CSV, the columns for assignee name, role, and creation date are missing from the output file. The export function maps only the fields defined in the original MVP (title, status, type) and was never updated when new columns were added to the task model. Users relying on CSV exports for reporting are getting incomplete data.", type: "bug", status: "done", assigneeRole: "Frontend Developer", projectName: "DevOps Pipeline" },
  { title: "Correct calculation in sprint burndown", description: "The sprint burndown chart shows incorrect remaining work calculations. Tasks that are moved back from 'done' to 'in_progress' are not being subtracted from the completed count, causing the burndown line to go below zero on some days. The calculation function uses a simple count of tasks that ever reached 'done' status instead of checking current status.", type: "bug", status: "waiting_approval", assigneeRole: "Tech Lead", projectName: "Pipelord Platform" },
  { title: "Correct date format in activity log", description: "The activity log displays dates in ISO 8601 format (2024-01-15T14:30:00.000Z) instead of a human-readable format. The timestamp is being rendered directly from the database without applying the date formatting utility. This affects all activity entries across the application and makes the log difficult to scan quickly.", type: "bug", status: "done", assigneeRole: "QA Engineer", projectName: "E-Commerce API" },
  { title: "Correct email template encoding issue", description: "Email notifications sent by the system display garbled characters for non-ASCII content. Names with accents, umlauts, or CJK characters appear as question marks or mojibake in the email body. The email template engine is not setting the Content-Type charset to UTF-8, defaulting to ISO-8859-1 encoding.", type: "bug", status: "done", assigneeRole: "Product Designer", projectName: "E-Commerce API" },
  { title: "Correct permission check on admin panel", description: "Non-admin users can access the admin panel by directly navigating to /admin in the browser. The route guard only checks authentication status but not the user's role. While the API endpoints correctly reject unauthorized requests, the admin UI still renders and shows a flash of admin content before the API errors cause the page to break.", type: "bug", status: "qa", assigneeRole: "Backend Developer", projectName: "Pipelord Platform" },
  { title: "Correct timezone offset in reports", description: "Generated reports show timestamps shifted by the server's timezone offset instead of the user's local timezone. All dates in exported reports appear in UTC, which confuses users in different timezones. The report generation service does not accept or apply a timezone parameter, and the frontend does not send the user's timezone with the report request.", type: "bug", status: "qa", assigneeRole: "Project Manager", projectName: "Marketing Site" },
  { title: "Fix 500 error when deleting a role with assigned workers", description: "Attempting to delete a role that still has workers assigned to it returns a 500 Internal Server Error. The delete endpoint does not check for existing foreign key references before attempting the deletion. PostgreSQL throws a foreign key constraint violation which is not caught or handled gracefully. The expected behavior is to return a 422 with a message explaining that workers must be reassigned first.", type: "bug", status: "todo", assigneeRole: "Project Manager", projectName: "Mobile App" },
  { title: "Fix CSS overflow on task cards", description: "Task cards on the Kanban board overflow their container when the task title exceeds 80 characters. The card component does not apply text truncation or word wrapping, causing horizontal scrolling on the column. This is most noticeable on tablet-width screens (768px-1024px) where column widths are narrower.", type: "bug", status: "waiting_approval", assigneeRole: "Frontend Developer", projectName: "DevOps Pipeline" },
  { title: "Fix broken avatar upload on mobile", description: "Avatar uploads from iOS Safari and Chrome on Android fail silently. The file input does not trigger the onChange handler on mobile browsers because the accept attribute is set to 'image/*' but the HEIC format from iPhones is not being converted. The upload request never reaches the server and no error feedback is shown to the user.", type: "bug", status: "waiting_approval", assigneeRole: "Frontend Developer", projectName: "DevOps Pipeline" },
  { title: "Fix broken pagination on tasks page", description: "The tasks list page shows incorrect results when navigating beyond page 2. The offset calculation multiplies page number by limit but does not subtract the limit, causing page 3 to show the same results as page 2. Additionally, the total count query does not apply the same filters as the data query, showing wrong total pages when filters are active.", type: "bug", status: "qa", assigneeRole: "QA Engineer", projectName: "E-Commerce API" },
  { title: "Fix broken redirect after logout", description: "After logging out, the user is redirected to /dashboard instead of /login. The logout server action clears the session cookie but the redirect path is hardcoded to the dashboard route. If the user's session has expired, they see a brief flash of the login page, then get redirected to dashboard, then back to login again, creating a visible flicker.", type: "bug", status: "in_progress", assigneeRole: "Tech Lead", projectName: "DevOps Pipeline" },
  { title: "Fix crash when submitting empty task description", description: "When an owner creates a new task on the Kanban board and leaves the description field empty before hitting \"Create\", the application throws an unhandled TypeError: Cannot read properties of undefined (reading 'trim'). The task creation server action does not validate whether the description field is present before attempting string operations on it. This causes the entire modal to freeze and requires a page refresh to recover. The expected behavior is that the description field should be optional and default to an empty string if not provided, as defined in the Prisma schema.", type: "bug", status: "todo", assigneeRole: "Tech Lead", projectName: "Unassigned" },
  { title: "Fix dark mode toggle persistence", description: "The dark mode toggle in the settings panel does not persist the user's preference across page reloads. The toggle updates the UI immediately using local state but does not save the preference to localStorage or the user's profile in the database. Every time the user refreshes the page, the theme reverts to the default light mode.", type: "bug", status: "in_progress", assigneeRole: "Project Manager", projectName: "DevOps Pipeline" },
  { title: "Fix drag and drop not working in Firefox", description: "The Kanban board drag and drop functionality does not work in Firefox. Tasks can be picked up but cannot be dropped into a different column. The issue is caused by the dragover event handler not calling event.preventDefault(), which is required in Firefox to allow the drop. Chrome and Safari handle this more permissively.", type: "bug", status: "done", assigneeRole: "QA Engineer", projectName: "Mobile App" },
  { title: "Fix duplicate notifications being sent", description: "Users receive duplicate email and in-app notifications when a task status changes. The notification trigger fires twice because the status update function emits the event before and after the database transaction commits. The second emission was added as a fallback but was never guarded against the first one succeeding.", type: "bug", status: "waiting_approval", assigneeRole: "Product Designer", projectName: "Pipelord Platform" },
  { title: "Fix file upload progress stuck at 99%", description: "The file upload progress bar gets stuck at 99% and never reaches 100%, even though the file is successfully uploaded. The progress callback from the upload library reports upload completion before the server sends its response. The UI waits for the server response to set 100% but the response handler has a race condition with the progress handler.", type: "bug", status: "done", assigneeRole: "QA Engineer", projectName: "E-Commerce API" },
  { title: "Fix horizontal scroll on mobile dashboard", description: "The dashboard page shows a horizontal scrollbar on screens narrower than 1024px. The Kanban board container has a fixed minimum width of 1200px set in an inline style that overrides the responsive Tailwind classes. This makes the dashboard unusable on tablets without constant horizontal scrolling.", type: "bug", status: "in_progress", assigneeRole: "Frontend Developer", projectName: "Marketing Site" },
  { title: "Fix login form validation error", description: "Users are able to submit the login form with an empty password field. The client-side validation regex is not matching correctly when the email contains a plus sign (e.g. user+test@example.com). This causes the form to bypass validation and hit the server, which returns a 422 but the error message is not displayed to the user.", type: "bug", status: "in_progress", assigneeRole: "Product Designer", projectName: "Marketing Site" },
  { title: "Fix missing error message on failed signup", description: "When user registration fails due to a duplicate email, the signup form shows a generic 'Something went wrong' message instead of 'Email already in use'. The error response from the server includes the specific error code DUPLICATE_EMAIL but the frontend error handler only checks for network errors and treats all 422 responses the same.", type: "bug", status: "done", assigneeRole: "Tech Lead", projectName: "DevOps Pipeline" },
  { title: "Fix missing validation on due date field", description: "The task creation form accepts due dates in the past without any warning or error. Users can set a due date to yesterday or even dates years in the past. The date input has no min attribute set and the server action does not validate that the due date is in the future. This causes confusion in sprint planning and burndown calculations.", type: "bug", status: "waiting_approval", assigneeRole: "Project Manager", projectName: "Mobile App" },
  { title: "Fix modal not closing on backdrop click", description: "Modal dialogs in the application do not close when clicking the backdrop overlay. The click event listener on the backdrop div is being prevented from firing because the modal content container has stopPropagation on its click handler, which also catches clicks that bubble up from the backdrop. Only the explicit close button works.", type: "bug", status: "qa", assigneeRole: "Frontend Developer", projectName: "Unassigned" },
  { title: "Fix notification sound not playing", description: "The notification sound effect does not play when new notifications arrive, even though the user has enabled sound notifications in settings. The Audio API call fails silently because modern browsers require a user gesture before allowing audio playback. The sound initialization happens on page load instead of on the first user interaction.", type: "bug", status: "qa", assigneeRole: "Product Manager", projectName: "Mobile App" },
  { title: "Fix search results not clearing on reset", description: "When a user clicks the 'Clear filters' button on the task search page, the search results from the previous query remain visible. The reset handler clears the filter state in the store but does not trigger a new fetch with empty parameters. The stale results stay in the UI until the user manually performs a new search.", type: "bug", status: "in_progress", assigneeRole: "Tech Lead", projectName: "Pipelord Platform" },
  { title: "Fix task card context menu closing immediately on click", description: "The right-click context menu on task cards opens and immediately closes. The menu component renders correctly for one frame before the global click-outside handler detects the right-click event and closes it. The click-outside hook does not distinguish between left and right mouse buttons.", type: "bug", status: "todo", assigneeRole: "QA Engineer", projectName: "E-Commerce API" },
  { title: "Fix tooltip clipping on sidebar", description: "Tooltips on the collapsed sidebar menu items are clipped by the sidebar container's overflow:hidden property. When the sidebar is collapsed to icon-only mode, hovering over a menu item shows a tooltip that is cut off at the sidebar boundary. The tooltip should use a portal to render outside the sidebar's overflow context.", type: "bug", status: "waiting_approval", assigneeRole: "Tech Lead", projectName: "Pipelord Platform" },
  { title: "Fix worker sidebar sorting inconsistency", description: "Workers in the sidebar are not sorted consistently. Sometimes they appear alphabetically, other times by role kanban_order. The sorting depends on which API response arrives first due to a race condition between the workers fetch and the roles fetch. The sidebar should always sort workers by their role's kanban_order.", type: "bug", status: "todo", assigneeRole: "Project Manager", projectName: "Pipelord Platform" },
  { title: "Optimize slow Kanban board loading with many tasks", description: "The Kanban board takes over 5 seconds to render when there are more than 100 tasks. The component re-renders all task cards on every status change because the task list is not memoized. Each card also makes individual API calls to fetch the assignee's avatar instead of using the data already available in the store.", type: "bug", status: "todo", assigneeRole: "QA Engineer", projectName: "DevOps Pipeline" },
  { title: "Resolve flaky WebSocket reconnection", description: "The WebSocket connection for real-time updates does not reliably reconnect after a network interruption. The reconnection logic uses a fixed 5-second interval but does not implement exponential backoff. After 3 failed attempts, it stops trying entirely. Users must refresh the page to restore real-time updates after losing connection briefly.", type: "bug", status: "waiting_approval", assigneeRole: "Frontend Developer", projectName: "Marketing Site" },
  { title: "Resolve inconsistent button states", description: "Action buttons across the application show inconsistent disabled/loading states. Some buttons show a spinner during async operations while others remain clickable, allowing double submissions. The submit button in the task creation form can be clicked multiple times before the server responds, creating duplicate tasks.", type: "bug", status: "in_progress", assigneeRole: "Product Manager", projectName: "E-Commerce API" },
  { title: "Resolve memory leak in dashboard polling", description: "The dashboard page leaks memory due to the 5-second polling interval not being cleaned up when the component unmounts. Each mount creates a new setInterval that continues running in the background. After navigating away and back to the dashboard several times, the accumulated intervals cause noticeable browser slowdown and excessive API calls.", type: "bug", status: "done", assigneeRole: "QA Engineer", projectName: "Marketing Site" },
  { title: "Resolve race condition in task assignment", description: "When two users simultaneously assign themselves to the same unassigned task, both assignments succeed and the task ends up with the last write winning silently. There is no optimistic locking or version check on the assignment operation. The expected behavior is that the second assignment should fail with a conflict error.", type: "bug", status: "qa", assigneeRole: "Frontend Developer", projectName: "Marketing Site" },
  { title: "Resolve stale cache after profile update", description: "After a user updates their profile (name or avatar), the old data continues to appear in the navigation bar and task cards until a full page reload. The profile update server action invalidates the profile cache but does not trigger a revalidation of the components that display user data. The stale data persists in the Zustand store.", type: "bug", status: "done", assigneeRole: "QA Engineer", projectName: "Mobile App" },

  // Features
  { title: "Add Slack integration", description: "Integrate with Slack to allow bidirectional communication between the Pipelord platform and Slack channels. When a task status changes, post an update to a configured Slack channel. Allow users to create tasks from Slack using a slash command. Support thread replies on task notifications to add comments back to the task in Pipelord.", type: "feature", status: "in_progress", assigneeRole: "Product Manager", projectName: "DevOps Pipeline" },
  { title: "Add agent performance analytics dashboard", description: "Build a dedicated analytics dashboard showing AI agent performance metrics. Display task completion rates per agent, average time in each status, throughput over time, and comparison charts between agents. Include filters by date range, task type, and agent role. Use server-side aggregation queries for performance.", type: "feature", status: "todo", assigneeRole: "QA Engineer", projectName: "E-Commerce API" },
  { title: "Add audit log viewer", description: "Create a searchable audit log viewer that displays all actions performed in the system. Log task creation, status changes, assignments, and configuration changes. Each entry should include timestamp, actor, action type, affected resource, and before/after values for changes. Support filtering by date range, actor, and action type.", type: "feature", status: "done", assigneeRole: "Product Manager", projectName: "Marketing Site" },
  { title: "Add bulk task operations", description: "Allow users to select multiple tasks on the Kanban board and perform bulk operations: change status, reassign, or delete. Add a selection mode toggle that shows checkboxes on task cards. Display a floating action bar at the bottom of the screen showing the count of selected tasks and available actions.", type: "feature", status: "in_progress", assigneeRole: "Backend Developer", projectName: "Mobile App" },
  { title: "Add calendar sync feature", description: "Add the ability to sync task due dates with external calendar services (Google Calendar, Outlook). Create a calendar settings page where users can connect their calendar accounts via OAuth. When a task has a due date, automatically create a calendar event. Update or remove calendar events when task dates change.", type: "feature", status: "waiting_approval", assigneeRole: "Tech Lead", projectName: "Marketing Site" },
  { title: "Add custom field definitions", description: "Allow administrators to define custom fields for tasks beyond the default title, description, type, and status. Support field types: text, number, date, single-select, and multi-select. Custom fields should appear in the task detail view, be filterable on the Kanban board, and be included in CSV exports.", type: "feature", status: "qa", assigneeRole: "Product Designer", projectName: "Pipelord Platform" },
  { title: "Add dark mode support", description: "Implement a system-wide dark mode theme. Create a dark color palette that maintains WCAG AA contrast ratios. Add a theme toggle in the settings panel that persists to localStorage and respects the OS-level prefers-color-scheme media query. Ensure all components, modals, and charts render correctly in dark mode.", type: "feature", status: "waiting_approval", assigneeRole: "Backend Developer", projectName: "E-Commerce API" },
  { title: "Add export task reports to PDF", description: "Allow users to export task reports as PDF documents. Include task details, status history, assignee information, and any comments. Support exporting individual tasks or filtered lists. Generate the PDF server-side using a headless browser or PDF library to ensure consistent rendering across platforms.", type: "feature", status: "todo", assigneeRole: "Product Manager", projectName: "E-Commerce API" },
  { title: "Add file attachment support", description: "Add the ability to attach files to tasks. Support drag-and-drop upload on the task detail view. Store files in an S3-compatible object storage service. Display file thumbnails for images and icons for other file types. Limit file size to 10MB per file and 50MB total per task.", type: "feature", status: "done", assigneeRole: "Tech Lead", projectName: "DevOps Pipeline" },
  { title: "Add keyboard shortcuts", description: "Implement keyboard shortcuts for common actions: N for new task, F for focus search, 1-5 for changing task status, arrow keys for navigating between columns and tasks, Enter to open task detail, Escape to close modals. Display a shortcuts cheat sheet when the user presses '?' key.", type: "feature", status: "qa", assigneeRole: "Backend Developer", projectName: "Mobile App" },
  { title: "Add multi-language support", description: "Implement internationalization (i18n) to support multiple languages in the UI. Start with English and Portuguese. Extract all user-facing strings into translation files. Use Next.js built-in i18n routing for locale detection and URL-based language switching. Ensure date, number, and currency formats respect the selected locale.", type: "feature", status: "done", assigneeRole: "Product Designer", projectName: "Mobile App" },
  { title: "Add real-time agent activity indicators on Kanban board", description: "Show real-time visual indicators on the Kanban board when AI agents are actively working on tasks. Display a pulsing animation on the task card, the agent's avatar with a 'working' status badge, and an estimated time remaining. Use the existing 5-second polling mechanism to update activity status.", type: "feature", status: "todo", assigneeRole: "QA Engineer", projectName: "DevOps Pipeline" },
  { title: "Add task approval workflow with owner review gates", description: "Implement a formal approval workflow where tasks in 'waiting_approval' status require explicit owner review. Add approve/reject buttons on task cards in this status. On approval, automatically advance the task to the next pipeline stage. On rejection, move back to the previous assignee with the rejection reason attached as a comment.", type: "feature", status: "todo", assigneeRole: "Project Manager", projectName: "DevOps Pipeline" },
  { title: "Add task priority levels", description: "Add priority levels (critical, high, medium, low) to tasks. Display priority with color-coded badges on task cards. Allow filtering and sorting by priority on the Kanban board. Include priority in the task creation form with medium as the default value.", type: "feature", status: "in_progress", assigneeRole: "Product Designer", projectName: "DevOps Pipeline" },
  { title: "Add time tracking feature", description: "Add time tracking capabilities to tasks. Allow workers to start/stop a timer on tasks they are assigned to. Display elapsed time on the task card and in the detail view. Provide a weekly timesheet view showing time spent per task and per worker. Store time entries with start/end timestamps for accurate reporting.", type: "feature", status: "qa", assigneeRole: "Tech Lead", projectName: "Mobile App" },
  { title: "Build milestone tracking with timeline visualization", description: "Create a milestone feature that groups related tasks into deliverables with target dates. Display milestones on a horizontal timeline with progress indicators showing percentage of completed tasks. Allow drilling down from a milestone to see its constituent tasks on the Kanban board filtered by that milestone.", type: "feature", status: "todo", assigneeRole: "Product Designer", projectName: "Pipelord Platform" },
  { title: "Build reusable task templates for common workflows", description: "Allow users to create and manage task templates for recurring workflows. A template defines a set of tasks with predefined titles, descriptions, types, and assignee roles. When instantiated, the template creates all tasks at once and assigns them to workers based on their roles. Include built-in templates for common patterns like 'New Feature' and 'Bug Fix'.", type: "feature", status: "todo", assigneeRole: "Project Manager", projectName: "Marketing Site" },
  { title: "Create activity timeline view", description: "Build a chronological timeline view showing all activity across the project. Display task creations, status changes, assignments, and comments in a scrollable feed. Support filtering by worker, task type, and date range. Include real-time updates using the existing polling mechanism.", type: "feature", status: "qa", assigneeRole: "Project Manager", projectName: "E-Commerce API" },
  { title: "Create custom report builder", description: "Build a report builder that allows users to create custom reports by selecting dimensions (worker, role, task type, status) and metrics (count, average time in status, completion rate). Support chart types: bar, line, pie, and table. Allow saving report configurations for reuse and scheduling automated email delivery.", type: "feature", status: "qa", assigneeRole: "Project Manager", projectName: "Unassigned" },
  { title: "Create email notification system", description: "Build an email notification system that alerts stakeholders on task status changes. Support configurable notification preferences per user: immediate, daily digest, or disabled. Use a job queue to process email sending asynchronously. Include task details, assignee info, and a direct link to the task in the email body.", type: "feature", status: "waiting_approval", assigneeRole: "Product Manager", projectName: "Mobile App" },
  { title: "Create onboarding wizard", description: "Build a step-by-step onboarding wizard for new users. Guide them through: creating their first project, understanding the agent roles, creating a sample task, and observing the automated pipeline. Use a progress indicator showing completed steps. Allow skipping the wizard with an option to restart it from settings.", type: "feature", status: "in_progress", assigneeRole: "Product Designer", projectName: "E-Commerce API" },
  { title: "Create performance dashboard", description: "Build a performance dashboard showing key metrics: tasks completed this week, average cycle time, tasks by status distribution, and worker utilization rates. Display data in charts and cards with sparklines showing trends. Support date range filtering and comparison with previous periods.", type: "feature", status: "in_progress", assigneeRole: "Product Designer", projectName: "E-Commerce API" },
  { title: "Create task dependency graph", description: "Implement task dependencies where a task can be marked as blocked by one or more other tasks. Display dependencies as a directed graph visualization. Prevent a task from moving to 'in_progress' if any of its blocking tasks are not 'done'. Show dependency chains in the task detail view.", type: "feature", status: "qa", assigneeRole: "Product Manager", projectName: "Unassigned" },
  { title: "Create team workload view", description: "Build a team workload view that shows how many tasks each worker has across different statuses. Display as a stacked bar chart or heatmap. Highlight workers who are overloaded (more than 5 active tasks) or idle (no active tasks). Allow managers to reassign tasks directly from this view by dragging between workers.", type: "feature", status: "qa", assigneeRole: "Backend Developer", projectName: "E-Commerce API" },
  { title: "Implement API rate limiting", description: "Add rate limiting to all API endpoints to prevent abuse. Implement sliding window rate limiting with configurable limits per endpoint group: authentication (10/min), reads (200/min), writes (50/min). Return 429 status with Retry-After header when limits are exceeded. Store rate limit counters in Redis.", type: "feature", status: "waiting_approval", assigneeRole: "Backend Developer", projectName: "Pipelord Platform" },
  { title: "Implement global task search with advanced filters", description: "Build a global search feature accessible via Cmd+K shortcut. Support full-text search across task titles and descriptions. Include advanced filters for status, type, assignee, date range, and priority. Show search results in a modal with keyboard navigation. Highlight matching text in results.", type: "feature", status: "todo", assigneeRole: "Project Manager", projectName: "Marketing Site" },
  { title: "Implement intelligent auto-assignment engine for AI agents", description: "Build an intelligent task assignment engine that automatically assigns tasks to the most appropriate AI agent based on their role, current workload, and task type. Consider agent availability, expertise matching, and round-robin distribution for balanced workloads. Log assignment decisions for transparency.", type: "feature", status: "todo", assigneeRole: "Product Designer", projectName: "Pipelord Platform" },
  { title: "Implement sprint planning board", description: "Create a sprint planning view where users can define sprints with start/end dates and drag tasks from the backlog into a sprint. Show sprint capacity based on the number of workers and their historical velocity. Display a sprint progress bar and burndown chart during active sprints.", type: "feature", status: "waiting_approval", assigneeRole: "Project Manager", projectName: "Marketing Site" },
  { title: "Implement task comments section", description: "Add a comments section to the task detail view. Allow workers and the owner to post comments with markdown support. Display comments in chronological order with the author's avatar and timestamp. Support @mentions that trigger notifications. Include an edit and delete option for the comment author.", type: "feature", status: "in_progress", assigneeRole: "Project Manager", projectName: "Unassigned" },
  { title: "Implement task recurrence", description: "Allow users to set tasks as recurring with configurable intervals: daily, weekly, biweekly, or monthly. When a recurring task is marked as done, automatically create a new instance with the same title, description, and assignee. Show a recurrence badge on task cards and the recurrence schedule in the detail view.", type: "feature", status: "in_progress", assigneeRole: "Project Manager", projectName: "Mobile App" },
  { title: "Implement user role management", description: "Build a role management interface where administrators can view all roles, edit role descriptions and colors, and control which workers are assigned to each role. Include a role detail page showing all workers with that role and their current tasks. Prevent deletion of roles that have active workers.", type: "feature", status: "qa", assigneeRole: "Product Designer", projectName: "DevOps Pipeline" },
  { title: "Implement webhook integrations", description: "Create a webhook system that sends HTTP POST notifications to configured URLs when events occur in the platform. Support events: task.created, task.status_changed, task.assigned, and task.completed. Include a webhook management UI for adding, testing, and disabling webhook endpoints. Implement retry logic with exponential backoff for failed deliveries.", type: "feature", status: "in_progress", assigneeRole: "Backend Developer", projectName: "Pipelord Platform" },
  { title: "Integrate OAuth authentication for team access", description: "Implement OAuth 2.0 authentication to allow team members to sign in with their Google or GitHub accounts. Support both login and signup flows. Map OAuth profiles to internal user accounts. Handle account linking when a user signs up with email first and later connects an OAuth provider.", type: "feature", status: "todo", assigneeRole: "Product Manager", projectName: "Mobile App" },

  // Tasks
  { title: "Audit and remediate npm dependency vulnerabilities", description: "Run npm audit and address all high and critical vulnerabilities. Update packages where patches are available. For vulnerabilities without patches, evaluate whether the affected code path is reachable in our application and document the risk assessment. Set up automated weekly vulnerability scanning in CI.", type: "task", status: "todo", assigneeRole: "Frontend Developer", projectName: "Mobile App" },
  { title: "Audit and rotate API keys", description: "Inventory all API keys and secrets used by the application: database credentials, third-party service keys (email provider, storage, monitoring), and internal service tokens. Verify that no secrets are committed to the repository or exposed in client-side bundles. Rotate all keys that are older than 90 days. Migrate to a secrets manager (AWS Secrets Manager or HashiCorp Vault) for centralized key management with automatic rotation.", type: "task", status: "waiting_approval", assigneeRole: "QA Engineer", projectName: "Marketing Site" },
  { title: "Conduct security audit of server actions and API surface", description: "Perform a comprehensive security audit of all Next.js server actions and API routes. Check for: missing authentication/authorization checks, SQL injection via raw queries, XSS through unescaped user input, CSRF protection, rate limiting, and proper input validation. Document findings with severity ratings and remediation steps.", type: "task", status: "todo", assigneeRole: "Product Designer", projectName: "Marketing Site" },
  { title: "Configure CDN for static assets", description: "Set up a CDN (CloudFront or Cloudflare) for serving static assets including images, fonts, and compiled JavaScript/CSS bundles. Configure proper cache headers with content-based hashing for cache busting. Set up a custom domain for the CDN. Measure and document the improvement in page load times from key geographic regions.", type: "task", status: "waiting_approval", assigneeRole: "Project Manager", projectName: "DevOps Pipeline" },
  { title: "Configure CORS policies", description: "Review and configure Cross-Origin Resource Sharing policies for all API endpoints. Define an allowlist of permitted origins based on deployment environments (localhost for dev, production domain, staging domain). Set appropriate allowed methods, headers, and credentials settings. Add CORS configuration tests to prevent regressions.", type: "task", status: "qa", assigneeRole: "Backend Developer", projectName: "Unassigned" },
  { title: "Configure rate limiting rules", description: "Implement application-level rate limiting for API endpoints using a sliding window algorithm backed by Redis. Configure tiered limits: authentication endpoints at 10 requests/minute per IP, read endpoints at 200 requests/minute per user, and write endpoints at 50 requests/minute per user. Return Retry-After headers on 429 responses. Add rate limit metrics to the monitoring dashboard and alert on sustained limit hits.", type: "task", status: "in_progress", assigneeRole: "Product Designer", projectName: "E-Commerce API" },
  { title: "Create database seed scripts", description: "Create comprehensive database seed scripts that populate the development database with realistic test data. Include all roles, workers with avatars, and a variety of tasks across all types and statuses. Ensure the seed is idempotent and can be run multiple times safely. Use Prisma for data operations.", type: "task", status: "qa", assigneeRole: "Frontend Developer", projectName: "DevOps Pipeline" },
  { title: "Create developer onboarding guide", description: "Write a developer onboarding guide covering: local environment setup (Node.js, Docker, database), project structure walkthrough, coding conventions and patterns, how to create new pages/components, testing strategy, and deployment process. Include troubleshooting tips for common setup issues.", type: "task", status: "done", assigneeRole: "Product Designer", projectName: "E-Commerce API" },
  { title: "Create health check and readiness probe endpoints", description: "Implement /health and /ready endpoints for container orchestration. The health endpoint should return 200 if the application process is running. The readiness endpoint should verify database connectivity, Redis availability, and any other critical dependencies. Return detailed status for each dependency in the response body.", type: "task", status: "todo", assigneeRole: "Product Designer", projectName: "Marketing Site" },
  { title: "Create runbook for incident response", description: "Write a detailed incident response runbook covering: severity classification (SEV1-SEV4) with response time SLAs, on-call rotation schedule and escalation paths, step-by-step investigation procedures for common failure modes (database outage, high error rate, deployment failure), communication templates for status page updates, post-incident review process, and a checklist for declaring an incident resolved.", type: "task", status: "qa", assigneeRole: "Tech Lead", projectName: "Pipelord Platform" },
  { title: "Document deployment procedures", description: "Document the complete deployment process from code merge to production. Include: pre-deployment checklist, environment-specific configuration, database migration steps, deployment commands, rollback procedures, and post-deployment verification steps. Cover both automated CI/CD pipeline deployments and manual emergency deployments.", type: "task", status: "qa", assigneeRole: "Frontend Developer", projectName: "Marketing Site" },
  { title: "Identify and resolve top technical debt items", description: "Conduct a tech debt audit across the codebase. Identify and address: TODO/FIXME comments older than 30 days, deprecated API usage, inconsistent error handling patterns, hardcoded configuration values that should be environment variables, unused imports and dead code, and components that have grown beyond 300 lines. Create a prioritized backlog of tech debt items and resolve the top 10 highest-impact issues.", type: "task", status: "todo", assigneeRole: "Backend Developer", projectName: "Pipelord Platform" },
  { title: "Implement automated PostgreSQL backup strategy", description: "Set up automated daily PostgreSQL backups using pg_dump with custom format for compression. Store backups in S3 with a 30-day retention policy. Implement point-in-time recovery capability using WAL archiving. Create and test a restoration script. Set up monitoring alerts for backup failures. Document the backup and restoration procedure.", type: "task", status: "todo", assigneeRole: "Project Manager", projectName: "Mobile App" },
  { title: "Migrate legacy data to new schema", description: "Write and execute migration scripts to transform data from the legacy schema to the new Prisma-managed schema. Handle data type conversions, null value defaults, and referential integrity. Create a validation script that compares record counts and checksums between old and new tables. Support rollback by keeping the legacy tables intact until migration is verified.", type: "task", status: "done", assigneeRole: "QA Engineer", projectName: "Marketing Site" },
  { title: "Optimize Docker production image for faster deployments", description: "Optimize the Docker production image to reduce build time and image size. Use multi-stage builds to separate build and runtime stages. Leverage layer caching for node_modules. Pin base image versions for reproducibility. Target an image size under 200MB and build time under 2 minutes. Add a .dockerignore to exclude test files and documentation.", type: "task", status: "todo", assigneeRole: "Tech Lead", projectName: "Unassigned" },
  { title: "Optimize database indexes", description: "Analyze slow queries using pg_stat_statements and EXPLAIN ANALYZE. Add indexes for frequently queried columns: tasks.status, tasks.assignee_id, tasks.type, and the composite index on tasks(status, assignee_id). Verify index usage with pg_stat_user_indexes. Document the before/after query performance improvements.", type: "task", status: "waiting_approval", assigneeRole: "Product Designer", projectName: "E-Commerce API" },
  { title: "Provision staging environment with automated deployments", description: "Set up a staging environment that mirrors production configuration. Configure automated deployments triggered on merges to the main branch. Include a separate PostgreSQL instance, environment-specific configuration, and a unique subdomain. Set up access controls so only the development team can access staging.", type: "task", status: "todo", assigneeRole: "Frontend Developer", projectName: "Unassigned" },
  { title: "Refactor data access layer to repository pattern", description: "Refactor direct Prisma calls scattered across server actions into a repository pattern. Create repository classes for each model (TaskRepository, WorkerRepository, RoleRepository) that encapsulate all database operations. This improves testability by allowing repository mocking and centralizes query logic.", type: "task", status: "todo", assigneeRole: "Tech Lead", projectName: "Pipelord Platform" },
  { title: "Refactor shared utility functions", description: "Audit and refactor shared utility functions spread across the codebase. Consolidate duplicate date formatting, string manipulation, and validation functions into a centralized utils directory. Add JSDoc comments and unit tests for each utility. Remove unused utilities identified during the audit.", type: "task", status: "qa", assigneeRole: "Tech Lead", projectName: "DevOps Pipeline" },
  { title: "Review code coverage gaps", description: "Generate a detailed code coverage report and identify areas below 80% coverage. Prioritize writing tests for: server actions handling task mutations, Zustand store logic, utility functions with branching logic, and error handling paths. Set up coverage thresholds in CI to prevent regressions below the target.", type: "task", status: "waiting_approval", assigneeRole: "Tech Lead", projectName: "Mobile App" },
  { title: "Set up CI/CD pipeline", description: "Configure a CI/CD pipeline using GitHub Actions. Include stages for: linting (ESLint), type checking (tsc --noEmit), unit tests (Jest), E2E tests (Playwright), build verification, and deployment to staging on main branch merges. Add caching for node_modules and Next.js build cache to speed up pipeline runs.", type: "task", status: "waiting_approval", assigneeRole: "Backend Developer", projectName: "DevOps Pipeline" },
  { title: "Set up application monitoring and alerting", description: "Set up application performance monitoring using a service like Datadog or New Relic. Instrument key server actions with custom metrics for response time and error rates. Configure alerts for: error rate above 1%, p95 latency above 2 seconds, and database connection pool exhaustion. Create a monitoring dashboard with key health indicators.", type: "task", status: "todo", assigneeRole: "Product Manager", projectName: "Mobile App" },
  { title: "Set up automated dependency updates", description: "Configure Dependabot or Renovate to automatically create PRs for dependency updates. Set up separate update schedules: security patches immediately, minor versions weekly, major versions monthly. Configure auto-merge for patch updates that pass CI. Group related packages (e.g., all @testing-library packages) into single PRs.", type: "task", status: "qa", assigneeRole: "Frontend Developer", projectName: "DevOps Pipeline" },
  { title: "Set up centralized structured logging", description: "Implement structured JSON logging across the application using a logging library like Pino. Replace all console.log/error calls with the structured logger. Include request ID, user ID, and action context in all log entries. Configure log levels per environment: debug for development, info for staging, warn for production.", type: "task", status: "todo", assigneeRole: "Backend Developer", projectName: "Unassigned" },
  { title: "Set up error tracking service", description: "Integrate an error tracking service (Sentry or Bugsnag) to capture and aggregate runtime errors. Configure source maps for readable stack traces in production. Set up error grouping rules to reduce noise from duplicate errors. Create alert rules for new error types and error rate spikes. Add user context to error reports for debugging.", type: "task", status: "done", assigneeRole: "Product Designer", projectName: "Unassigned" },
  { title: "Set up feature flag system", description: "Implement a feature flag system to control feature rollouts. Support flag types: boolean (on/off), percentage (gradual rollout), and user-segment (specific users). Create a management UI for toggling flags. Integrate with the application so components can conditionally render based on flag values. Include flag evaluation logging for debugging.", type: "task", status: "waiting_approval", assigneeRole: "Product Designer", projectName: "Marketing Site" },
  { title: "Set up load testing infrastructure", description: "Set up load testing using k6 or Artillery. Create test scripts for critical user flows: dashboard loading, task creation, status updates, and search. Establish baseline performance metrics under normal load (100 concurrent users) and stress test limits. Integrate load tests into the CI pipeline for regression detection.", type: "task", status: "done", assigneeRole: "Project Manager", projectName: "Pipelord Platform" },
  { title: "Set up performance benchmarks", description: "Establish performance benchmarks for critical user flows: dashboard initial load under 1.5 seconds, task list rendering under 500ms for 200 items, search results under 300ms, and task creation under 200ms. Set up automated Lighthouse CI checks on every PR measuring Core Web Vitals (LCP, FID, CLS). Create a performance tracking dashboard showing trends over the last 30 days of deployments.", type: "task", status: "qa", assigneeRole: "Product Manager", projectName: "Marketing Site" },
  { title: "Update dependencies to latest versions", description: "Update all npm dependencies to their latest compatible versions. Run the full test suite after each major dependency update to catch breaking changes. Pay special attention to Next.js, React, Prisma, and Tailwind CSS updates. Document any breaking changes and required code modifications in the PR description.", type: "task", status: "done", assigneeRole: "Backend Developer", projectName: "Mobile App" },
  { title: "Write API documentation", description: "Document all server actions and their expected inputs/outputs. Include parameter types, return types, error codes, and example request/response payloads. Use a documentation format that can be auto-generated from TypeScript types where possible. Host the documentation alongside the application.", type: "task", status: "in_progress", assigneeRole: "Product Designer", projectName: "DevOps Pipeline" },
  { title: "Write E2E tests for auth flow", description: "Write Playwright E2E tests covering the complete authentication flow: signup with valid data, signup with duplicate email, login with valid credentials, login with wrong password, session persistence across page reloads, and logout. Include tests for protected route redirects when not authenticated.", type: "task", status: "done", assigneeRole: "Backend Developer", projectName: "E-Commerce API" },
  { title: "Write integration tests for API", description: "Write integration tests for all server actions using a test database. Cover success paths, validation errors, not-found cases, and authorization checks. Use database transactions that roll back after each test for isolation. Test edge cases: empty strings, very long inputs, special characters, and concurrent modifications.", type: "task", status: "in_progress", assigneeRole: "Backend Developer", projectName: "DevOps Pipeline" },
  { title: "Write migration rollback scripts", description: "Create rollback scripts for each Prisma migration that can safely reverse schema changes. Test each rollback script against a database with production-like data. Document the rollback procedure and any data loss implications. Store rollback scripts alongside their corresponding migrations for easy access during incidents.", type: "task", status: "in_progress", assigneeRole: "Product Designer", projectName: "Unassigned" },
  { title: "Write unit tests for user service", description: "Write comprehensive unit tests for the user service covering: user creation with valid data, validation errors for missing fields, duplicate email handling, user update operations, and user deletion with cascade behavior. Mock the Prisma client to isolate the service logic from the database.", type: "task", status: "qa", assigneeRole: "Product Manager", projectName: "DevOps Pipeline" },

  // Security Analyst tasks
  { title: "Fix exposed stack traces in production error responses", description: "Server actions return full stack traces and internal file paths in error responses when running in production mode. The global error handler does not strip debug information from the response body before sending it to the client. An attacker can use the exposed file paths, dependency versions, and SQL fragments to map the internal architecture and identify known vulnerabilities in specific package versions.", type: "bug", status: "in_progress", assigneeRole: "Security Analyst", projectName: "E-Commerce API" },
  { title: "Fix insecure direct object reference in task detail endpoint", description: "The task detail server action accepts a task ID parameter and returns the full task record without verifying that the requesting user has access to the project the task belongs to. Any authenticated user can enumerate task IDs and read task titles, descriptions, and assignee information from projects they are not a member of. The action should validate project membership before returning task data.", type: "bug", status: "todo", assigneeRole: "Security Analyst", projectName: "E-Commerce API" },
  { title: "Fix missing rate limiting on authentication endpoints", description: "The login and signup server actions have no rate limiting applied. An attacker can send thousands of login attempts per minute from a single IP address without being throttled or blocked. The lack of rate limiting makes brute-force credential attacks feasible. Implement rate limiting with a sliding window of 10 requests per minute per IP for authentication endpoints and return HTTP 429 after the threshold is exceeded.", type: "bug", status: "qa", assigneeRole: "Security Analyst", projectName: "Marketing Site" },
  { title: "Fix session tokens stored in localStorage without encryption", description: "User session tokens are stored in localStorage as plain text strings. Any XSS vulnerability in the application or in a third-party script loaded on the page can read the token and hijack the user session. The token should be stored in an HttpOnly, Secure, SameSite=Strict cookie instead of localStorage to prevent client-side JavaScript from accessing it. Existing localStorage tokens should be migrated and invalidated.", type: "bug", status: "waiting_approval", assigneeRole: "Security Analyst", projectName: "E-Commerce API" },
  { title: "Implement Content Security Policy headers", description: "Define and deploy a strict Content Security Policy (CSP) to mitigate cross-site scripting and data injection attacks. Configure directives for script-src, style-src, img-src, connect-src, font-src, and frame-ancestors. Start with report-only mode to identify violations without breaking existing functionality. Set up a CSP violation reporting endpoint to collect and analyze policy violations before switching to enforcement mode.", type: "feature", status: "todo", assigneeRole: "Security Analyst", projectName: "Marketing Site" },
  { title: "Implement automated dependency vulnerability scanning", description: "Integrate Snyk or GitHub Dependabot security alerts into the CI pipeline to automatically scan npm dependencies for known CVEs on every pull request. Configure severity thresholds to block merges when critical or high vulnerabilities are detected. Set up a weekly scheduled scan for the main branch to catch newly disclosed vulnerabilities in existing dependencies. Generate a dependency security report showing current vulnerability count by severity.", type: "feature", status: "in_progress", assigneeRole: "Security Analyst", projectName: "DevOps Pipeline" },
  { title: "Add audit logging for sensitive operations", description: "Implement a comprehensive audit trail for all security-sensitive operations: login attempts (successful and failed), password changes, role assignments, project membership changes, task deletions, and admin panel access. Each audit entry should capture the actor ID, action performed, target resource, IP address, user agent, and timestamp. Store audit logs in a separate database table with append-only access to prevent tampering.", type: "feature", status: "done", assigneeRole: "Security Analyst", projectName: "E-Commerce API" },
  { title: "Conduct OWASP Top 10 assessment on server actions", description: "Perform a structured security assessment of all Next.js server actions against the OWASP Top 10 2021 checklist. Test for injection flaws in Prisma queries that use raw SQL or unsanitized user input, broken authentication in session handling, sensitive data exposure in API responses, security misconfiguration in Next.js headers, and cross-site request forgery in state-changing actions. Document each finding with severity, proof of concept, and remediation steps.", type: "task", status: "waiting_approval", assigneeRole: "Security Analyst", projectName: "DevOps Pipeline" },
  { title: "Configure secrets management and rotation policy", description: "Audit all environment variables and hardcoded secrets in the codebase. Migrate secrets from .env files to a centralized secrets manager such as HashiCorp Vault or AWS Secrets Manager. Define a rotation schedule: database credentials every 90 days, API keys every 180 days, JWT signing keys every 365 days. Implement automated rotation scripts and update deployment pipelines to pull secrets at runtime instead of build time.", type: "task", status: "done", assigneeRole: "Security Analyst", projectName: "Pipelord Platform" },
  { title: "Write security incident response runbook", description: "Create a detailed incident response runbook covering the five phases: identification, containment, eradication, recovery, and lessons learned. Define severity levels (P1 through P4) with corresponding response time SLAs and escalation paths. Include step-by-step procedures for common scenarios: compromised credentials, data breach, DDoS attack, and supply chain compromise. List all relevant contacts, communication channels, and tools required during an incident.", type: "task", status: "todo", assigneeRole: "Security Analyst", projectName: "Mobile App" },
  { title: "Write API reference documentation for task endpoints", description: "Create comprehensive API reference documentation covering all task-related endpoints: create, read, update, delete, list with filters, and status transitions. Each endpoint entry should include the HTTP method, URL path, request parameters, request body schema with examples, response schema with examples, error codes, and authentication requirements. Use OpenAPI 3.0 format and ensure all field descriptions match the current Prisma schema.", type: "task", status: "done", assigneeRole: "Technical Writer", projectName: "Mobile App" },
  { title: "Write quickstart setup guide for new contributors", description: "Write a step-by-step quickstart guide for new contributors joining the project. Cover environment setup (Node.js, Docker, PostgreSQL), repository cloning, dependency installation, database migration and seeding, running the development server, and executing tests. Include troubleshooting tips for common setup issues like port conflicts, Docker permission errors, and Prisma generation failures. The guide should enable a new contributor to go from zero to running the app in under 30 minutes.", type: "task", status: "in_progress", assigneeRole: "Technical Writer", projectName: "Unassigned" },
  { title: "Document agent roles and pipeline workflow", description: "Create a detailed guide explaining each AI agent role, their responsibilities, the order in which they participate in the task pipeline, and the status transitions that occur at each stage. Include a visual flowchart showing the task lifecycle from creation to completion, with decision points for approval gates. Describe how tasks move between agents and what artifacts each agent produces at their stage.", type: "feature", status: "waiting_approval", assigneeRole: "Technical Writer", projectName: "Mobile App" },
  { title: "Fix outdated database schema documentation", description: "The existing database documentation references columns and tables that were renamed or removed during the last migration cycle. The Agent table still shows a 'rules' column that was dropped, and the Task table documentation does not include the 'projectId' foreign key or the 'type' enum values. Update all schema documentation to match the current Prisma schema exactly, including field types, constraints, default values, and relationships.", type: "bug", status: "todo", assigneeRole: "Technical Writer", projectName: "DevOps Pipeline" },
  { title: "Write Kanban board user guide", description: "Create an end-user guide for the Kanban board interface covering task card anatomy, column meanings, filtering by agent, drag-and-drop interactions, and keyboard shortcuts. Include annotated screenshots showing each feature in action. Explain the status workflow and what each transition means for the task lifecycle. Target audience is non-technical project owners who interact with the board daily.", type: "feature", status: "qa", assigneeRole: "Technical Writer", projectName: "DevOps Pipeline" },
  { title: "Create architecture decision records template and backlog", description: "Establish an Architecture Decision Records (ADR) practice by creating a standardized template and documenting the key architectural decisions already made: choice of Next.js App Router, Zustand for state management, short-polling over WebSockets, Prisma as ORM, and the agent-based task pipeline. Each ADR should capture context, decision, alternatives considered, consequences, and status. Set up a numbered index for easy reference.", type: "task", status: "todo", assigneeRole: "Technical Writer", projectName: "Marketing Site" },
  { title: "Fix incorrect code examples in contributing guidelines", description: "Several code examples in the contributing guidelines use outdated patterns that no longer match the codebase conventions. The examples show class components instead of functional components, use require instead of import, and reference the old database client initialization without the PG adapter. Developers following these examples produce code that fails linting and type checks. Update all examples to reflect the current tech stack and coding standards.", type: "bug", status: "in_progress", assigneeRole: "Technical Writer", projectName: "DevOps Pipeline" },
  { title: "Document environment variables and configuration", description: "Create a comprehensive configuration reference listing every environment variable used by the application. For each variable, document its name, purpose, expected format, default value, whether it is required or optional, and which services depend on it. Include a sample .env.example file with commented explanations. Cover DATABASE_URL, PORT, NODE_ENV, and any API keys or feature flags currently in use.", type: "feature", status: "done", assigneeRole: "Technical Writer", projectName: "Unassigned" },
];
